"use client"

import * as React from "react"
import type { IconSvgElement } from "@hugeicons/react"

import { Card } from "@/components/ui/card"
import { cn } from "@/lib/utils"

/* ── Types ── */

export interface ComposerTask {
  label: string
  done: boolean
  dimmed?: boolean
}

export interface ComposerFile {
  name: string
  size: string
  type: "file" | "image"
}

export interface ComposerScopeItem {
  id: string
  label: string
  icon: IconSvgElement
}

/* ── Context ── */

interface ComposerContextValue {
  value: string
  onValueChange: (value: string) => void
  isSending: boolean
  send: () => void
  disabled: boolean
  textareaRef: React.RefObject<HTMLTextAreaElement | null>
}

const ComposerContext = React.createContext<ComposerContextValue | null>(null)

export function useComposer(): ComposerContextValue {
  const ctx = React.useContext(ComposerContext)
  if (!ctx) {
    throw new Error("useComposer must be used within a <Composer />")
  }
  return ctx
}

/* ── Composer (root) ── */

export function Composer({
  value: valueProp,
  defaultValue = "",
  onValueChange: onValueChangeProp,
  onSend,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  onSend?: (value: string) => void
  disabled?: boolean
}) {
  const [_value, _setValue] = React.useState(defaultValue)
  const value = valueProp ?? _value
  const onValueChange = React.useCallback(
    (v: string) => {
      if (onValueChangeProp) onValueChangeProp(v)
      else _setValue(v)
    },
    [onValueChangeProp],
  )

  const [isSending, setIsSending] = React.useState(false)
  const textareaRef = React.useRef<HTMLTextAreaElement | null>(null)

  const send = React.useCallback(() => {
    if (disabled) return
    if (!value.trim()) return
    setIsSending(true)
    const currentValue = value
    setTimeout(() => {
      onValueChange("")
      setIsSending(false)
      if (textareaRef.current) textareaRef.current.style.height = "auto"
    }, 400)
    onSend?.(currentValue)
  }, [value, disabled, onValueChange, onSend])

  const ctx = React.useMemo<ComposerContextValue>(
    () => ({
      value,
      onValueChange,
      isSending,
      send,
      disabled,
      textareaRef,
    }),
    [value, onValueChange, isSending, send, disabled],
  )

  return (
    <ComposerContext.Provider value={ctx}>
      <div
        data-slot="composer"
        className={cn(
          "mx-auto flex w-full max-w-[720px] flex-col items-center",
          className,
        )}
        {...props}
      >
        {children}
      </div>
    </ComposerContext.Provider>
  )
}

/* ── ComposerIslands ── */

export function ComposerIslands({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="composer-islands"
      className={cn(
        "flex w-full flex-col items-center",
        "[&>[data-slot=composer-island-wrapper]]:w-[95%]",
        "[&>[data-slot=composer-island-wrapper]_[data-slot=composer-island]]:rounded-b-none",
        "[&>[data-slot=composer-island-wrapper]:not(:first-child)_[data-slot=composer-island]]:rounded-t-none",
        className,
      )}
      {...props}
    >
      {children}
    </div>
  )
}

/* ── ComposerCard ── */

export function ComposerCard({
  className,
  children,
  ...props
}: React.ComponentProps<typeof Card>) {
  return (
    <Card
      data-slot="composer-card"
      size="sm"
      className={cn("relative z-1 w-full gap-0 py-0", className)}
      {...props}
    >
      {children}
    </Card>
  )
}

/* ── Re-exports ── */

export { ComposerInput } from "./composer-input"
export {
  ComposerToolbar,
  ComposerMenu,
  ComposerContextRing,
  ComposerSend,
} from "./composer-toolbar"
export {
  ComposerScope,
  ComposerReply,
  ComposerPlan,
} from "./composer-islands"
export { ComposerAttachments } from "./composer-attachments"
export { ComposerSuggestions } from "./composer-suggestions"

"use client"

import * as React from "react"

import { Textarea } from "@/components/ui/textarea"
import { cn } from "@/lib/utils"
import { useComposer } from "./composer"

export function ComposerInput({
  placeholder = "Type a message...",
  maxHeight = 160,
  className,
  ...props
}: Omit<React.ComponentProps<"textarea">, "value" | "onChange"> & {
  maxHeight?: number
}) {
  const { value, onValueChange, send, textareaRef } = useComposer()

  React.useEffect(() => {
    const ta = textareaRef.current
    if (!ta) return
    ta.style.height = "auto"
    ta.style.height = Math.min(ta.scrollHeight, maxHeight) + "px"
  }, [value, maxHeight, textareaRef])

  return (
    <div
      data-slot="composer-input"
      className={cn("px-4 pt-3 pb-1", className)}
    >
      <Textarea
        ref={textareaRef}
        value={value}
        onChange={(e) => onValueChange(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === "Enter" && !e.shiftKey) {
            e.preventDefault()
            send()
          }
        }}
        placeholder={placeholder}
        rows={1}
        className="min-h-[32px] resize-none border-0 bg-transparent px-0 py-0 shadow-none focus-visible:border-transparent focus-visible:ring-0"
        style={{ maxHeight }}
        {...props}
      />
    </div>
  )
}

"use client"

import * as React from "react"
import { HugeiconsIcon } from "@hugeicons/react"
import { ArrowUp02Icon, Add01Icon } from "@hugeicons/core-free-icons"

import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"
import { useComposer } from "./composer"

/* ── ComposerToolbar ── */

export function ComposerToolbar({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="composer-toolbar"
      className={cn("flex items-center gap-1 px-3 pt-0.5 pb-3", className)}
      {...props}
    >
      {children}
    </div>
  )
}

/* ── ComposerMenu ── */

export function ComposerMenu({
  className,
  children,
}: {
  children: React.ReactNode
  className?: string
}) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger
        render={<Button variant="ghost" size="icon-sm" className={className} />}
      >
        <HugeiconsIcon icon={Add01Icon} size={16} strokeWidth={1.5} />
      </DropdownMenuTrigger>
      <DropdownMenuContent
        side="top"
        sideOffset={8}
        align="start"
        className="min-w-[220px]"
      >
        {children}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

/* ── ComposerContextRing ── */

export function ComposerContextRing({
  used,
  total,
  label,
  className,
  ...props
}: React.ComponentProps<typeof TooltipTrigger> & {
  used: number
  total: number
  label?: string
}) {
  const pct = total > 0 ? used / total : 0
  const r = 6
  const circ = 2 * Math.PI * r
  const offset = circ * (1 - pct)
  const displayLabel = label ?? `${used}k / ${total}k tokens`
  const pctLabel = `${Math.round(pct * 100)}%`

  return (
    <Tooltip>
      <TooltipTrigger
        render={
          <Button
            type="button"
            variant="ghost"
            size="icon-sm"
            className={cn("mr-1", className)}
          />
        }
        {...props}
      >
        <svg width="16" height="16" viewBox="0 0 16 16">
          <circle
            cx="8"
            cy="8"
            r={r}
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
            opacity="0.15"
          />
          <circle
            cx="8"
            cy="8"
            r={r}
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeDasharray={circ}
            strokeDashoffset={offset}
            strokeLinecap="round"
            transform="rotate(-90 8 8)"
            className="text-muted-foreground"
          />
        </svg>
      </TooltipTrigger>
      <TooltipContent side="top" sideOffset={8}>
        <span>
          {displayLabel} ({pctLabel})
        </span>
      </TooltipContent>
    </Tooltip>
  )
}

/* ── ComposerSend ── */

export function ComposerSend({
  className,
  ...props
}: React.ComponentProps<typeof Button>) {
  const { value, isSending, send } = useComposer()
  const [arrowAnim, setArrowAnim] = React.useState(false)
  const hasContent = value.trim().length > 0

  const handleClick = React.useCallback(() => {
    setArrowAnim(true)
    send()
    setTimeout(() => setArrowAnim(false), 500)
  }, [send])

  return (
    <Button
      data-slot="composer-send"
      type="button"
      size="icon-sm"
      onClick={handleClick}
      disabled={!hasContent}
      className={cn(isSending ? "animate-composer-send" : "", className)}
      {...props}
    >
      <span className={arrowAnim ? "animate-composer-arrow" : ""}>
        <HugeiconsIcon icon={ArrowUp02Icon} size={15} strokeWidth={2} />
      </span>
    </Button>
  )
}

"use client"

import * as React from "react"
import { HugeiconsIcon } from "@hugeicons/react"
import {
  ArrowExpand01Icon,
  ArrowShrink01Icon,
  Cancel01Icon,
  MailReply01Icon,
  Task01Icon,
} from "@hugeicons/core-free-icons"

import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card } from "@/components/ui/card"
import { cn } from "@/lib/utils"
import type { ComposerScopeItem, ComposerTask } from "./composer"

function Island({
  className,
  children,
  ...props
}: React.ComponentProps<typeof Card>) {
  return (
    <div
      data-slot="composer-island-wrapper"
      className={cn("animate-composer-island", className)}
      style={{ zIndex: 0 }}
    >
      <Card
        data-slot="composer-island"
        size="sm"
        className="gap-0 py-0"
        {...props}
      >
        {children}
      </Card>
    </div>
  )
}

export function ComposerScope({
  items,
  onRemove,
  onDismiss,
  className,
  ...props
}: React.ComponentProps<typeof Island> & {
  items: ComposerScopeItem[]
  onRemove?: (id: string) => void
  onDismiss?: () => void
}) {
  return (
    <Island className={className} {...props}>
      <div className="flex items-center gap-2 px-4 py-3">
        <div className="flex min-w-0 flex-1 flex-wrap items-center gap-2">
          {items.map((item) => (
            <Badge key={item.id} variant="outline">
              <HugeiconsIcon icon={item.icon} size={12} strokeWidth={1.5} />
              <span className="max-w-[160px] truncate">{item.label}</span>
              {onRemove && (
                <Button
                  type="button"
                  variant="ghost"
                  size="icon-xs"
                  onClick={() => onRemove(item.id)}
                  className="size-4"
                >
                  <HugeiconsIcon icon={Cancel01Icon} size={10} strokeWidth={2} />
                </Button>
              )}
            </Badge>
          ))}
        </div>
        {onDismiss && (
          <Button
            type="button"
            variant="ghost"
            size="icon-xs"
            onClick={onDismiss}
          >
            <HugeiconsIcon icon={Cancel01Icon} size={14} strokeWidth={1.5} />
          </Button>
        )}
      </div>
    </Island>
  )
}

export function ComposerReply({
  onDismiss,
  className,
  children,
  ...props
}: React.ComponentProps<typeof Island> & {
  onDismiss?: () => void
}) {
  return (
    <Island className={className} {...props}>
      <div className="flex items-center gap-3 px-4 py-3">
        <Badge variant="outline">
          <HugeiconsIcon icon={MailReply01Icon} size={12} strokeWidth={1.5} />
          Reply
        </Badge>
        <span className="flex-1 truncate text-sm text-muted-foreground">
          {children}
        </span>
        {onDismiss && (
          <Button
            type="button"
            variant="ghost"
            size="icon-xs"
            onClick={onDismiss}
          >
            <HugeiconsIcon icon={Cancel01Icon} size={14} strokeWidth={1.5} />
          </Button>
        )}
      </div>
    </Island>
  )
}

export function ComposerPlan({
  tasks,
  defaultExpanded = false,
  className,
  ...props
}: React.ComponentProps<typeof Island> & {
  tasks: ComposerTask[]
  defaultExpanded?: boolean
}) {
  const [expanded, setExpanded] = React.useState(defaultExpanded)
  const completedCount = tasks.filter((t) => t.done).length

  return (
    <Island className={className} {...props}>
      <div className="px-4 py-3">
        <div className="flex items-center justify-between gap-3">
          <div className="flex min-w-0 items-center gap-2 text-sm text-muted-foreground">
            <Badge variant="outline">Plan</Badge>
            <div className="flex min-w-0 items-center gap-2">
              <HugeiconsIcon icon={Task01Icon} size={14} strokeWidth={1.5} />
              <span className="truncate">
                {completedCount} out of {tasks.length} tasks completed
              </span>
            </div>
          </div>
          <Button
            type="button"
            variant="ghost"
            size="icon-xs"
            onClick={() => setExpanded(!expanded)}
          >
            <HugeiconsIcon
              icon={expanded ? ArrowShrink01Icon : ArrowExpand01Icon}
              size={14}
              strokeWidth={1.5}
            />
          </Button>
        </div>

        {expanded && (
          <div className="animate-composer-slide mt-3 space-y-3">
            {tasks.map((task, i) => (
              <div
                key={i}
                className={cn(
                  "flex items-start gap-3 text-sm",
                  task.dimmed ? "text-muted-foreground" : "text-foreground",
                )}
              >
                <span
                  className={cn(
                    "mt-1 flex h-4 w-4 shrink-0 items-center justify-center rounded-full border",
                    task.done ? "bg-primary text-primary-foreground" : "",
                  )}
                />
                <span>
                  {i + 1}. {task.label}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>
    </Island>
  )
}

"use client"

import * as React from "react"
import { HugeiconsIcon } from "@hugeicons/react"
import {
  Cancel01Icon,
  File01Icon,
  Image01Icon,
} from "@hugeicons/core-free-icons"

import { Button } from "@/components/ui/button"
import { Card } from "@/components/ui/card"
import { cn } from "@/lib/utils"
import type { ComposerFile } from "./composer"

const FILE_ICONS = {
  file: File01Icon,
  image: Image01Icon,
} as const

export function ComposerAttachments({
  files,
  onRemove,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  files: ComposerFile[]
  onRemove?: (name: string) => void
}) {
  if (files.length === 0) return null

  return (
    <div
      data-slot="composer-attachments"
      className={cn("animate-composer-slide flex gap-2 px-4 pt-3 pb-1", className)}
      {...props}
    >
      {files.map((file) => (
        <Card key={file.name} size="sm" className="gap-0 px-3 py-2">
          <div className="flex items-center gap-2">
            <HugeiconsIcon
              icon={FILE_ICONS[file.type]}
              size={14}
              strokeWidth={1.5}
            />
            <div className="min-w-0">
              <p className="max-w-[140px] truncate text-sm">{file.name}</p>
              <p className="text-xs text-muted-foreground">{file.size}</p>
            </div>
            {onRemove && (
              <Button
                type="button"
                variant="ghost"
                size="icon-xs"
                onClick={() => onRemove(file.name)}
              >
                <HugeiconsIcon
                  icon={Cancel01Icon}
                  size={12}
                  strokeWidth={1.5}
                />
              </Button>
            )}
          </div>
        </Card>
      ))}
    </div>
  )
}

"use client"

import * as React from "react"

import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"
import { useComposer } from "./composer"

export function ComposerSuggestions({
  items,
  onSelect,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  items: string[]
  onSelect?: (suggestion: string) => void
}) {
  const { onValueChange, textareaRef } = useComposer()
  const [flashChip, setFlashChip] = React.useState<string | null>(null)

  const handleClick = React.useCallback(
    (suggestion: string) => {
      setFlashChip(suggestion)
      setTimeout(() => {
        onValueChange(suggestion)
        setFlashChip(null)
        textareaRef.current?.focus()
        onSelect?.(suggestion)
      }, 250)
    },
    [onValueChange, textareaRef, onSelect],
  )

  if (items.length === 0) return null

  return (
    <div
      data-slot="composer-suggestions"
      className={cn(
        "animate-composer-slide mt-3 flex flex-wrap justify-center gap-2",
        className,
      )}
      {...props}
    >
      {items.map((s) => (
        <Button
          key={s}
          type="button"
          variant="outline"
          size="xs"
          onClick={() => handleClick(s)}
          className={cn(flashChip === s ? "animate-composer-chip" : "")}
        >
          {s}
        </Button>
      ))}
    </div>
  )
}
